import React, { useRef, useEffect, useState } from "react";
import axios from "axios";
import { Holistic } from "@mediapipe/holistic";
import { Camera } from "@mediapipe/camera_utils";
import * as drawingUtils from "@mediapipe/drawing_utils";

const SEQUENCE_LENGTH = 30;
const FEATURE_SIZE = 225;
const CONFIDENCE_THRESHOLD = 0.8;

const TranslationPage = () => {
  const videoRef = useRef(null);
  const canvasRef = useRef(null);
  const bufferRef = useRef([]);
  const sendingRef = useRef(false);

  const [currentPrediction, setCurrentPrediction] = useState("");
  const [sentence, setSentence] = useState("");
  const [error, setError] = useState("");

  // Normalize landmarks function
  const normalize = (coords) => {
    const reshaped = coords.reduce((arr, point) => [...arr, ...point], []);
    const base = reshaped.slice(0, 3); // base landmark for normalization
    for (let i = 0; i < reshaped.length; i += 3) {
      reshaped[i] -= base[0]; // Normalize x
      reshaped[i + 1] -= base[1]; // Normalize y
      reshaped[i + 2] -= base[2]; // Normalize z
    }
    return reshaped;
  };

  // Process the results from MediaPipe
  const onResults = async (results) => {
    const left = Array(63).fill(0);
    const right = Array(63).fill(0);
    const pose = Array(99).fill(0);

    // Normalize and prepare left hand landmarks
    if (results.leftHandLandmarks) {
      const norm = normalize(results.leftHandLandmarks.map(lm => [lm.x, lm.y, lm.z]));
      for (let i = 0; i < 63; i++) left[i] = norm[i];
    }

    // Normalize and prepare right hand landmarks
    if (results.rightHandLandmarks) {
      const norm = normalize(results.rightHandLandmarks.map(lm => [lm.x, lm.y, lm.z]));
      for (let i = 0; i < 63; i++) right[i] = norm[i];
    }

    // Normalize and prepare pose landmarks
    if (results.poseLandmarks) {
      const norm = normalize(results.poseLandmarks.slice(0, 33).map(lm => [lm.x, lm.y, lm.z]));
      for (let i = 0; i < 99; i++) pose[i] = norm[i];
    }

    const combined = [...left, ...right, ...pose];

    if (combined.length === FEATURE_SIZE) {
      bufferRef.current.push(combined);
      if (bufferRef.current.length > SEQUENCE_LENGTH) {
        bufferRef.current.shift();
      }

      // Send data to backend once the buffer reaches 30 frames
      if (
        bufferRef.current.length === SEQUENCE_LENGTH &&
        !sendingRef.current
      ) {
        sendingRef.current = true;
        try {
          const res = await axios.post("http://localhost:8000/predict", {
            sequence: bufferRef.current,
          });
          const { word, confidence } = res.data;

          if (confidence >= CONFIDENCE_THRESHOLD) {
            setCurrentPrediction(`${word} (${(confidence * 100).toFixed(1)}%)`);
            setSentence((prev) => `${prev} ${word}`);
          } else {
            setCurrentPrediction("Detecting...");
          }
        } catch (err) {
          console.error("Prediction error:", err);
          setError("Prediction failed. Check backend or model.");
        } finally {
          bufferRef.current = [];
          sendingRef.current = false;
        }
      }
    }

    // === Draw landmarks ===
    const canvas = canvasRef.current;
    const ctx = canvas.getContext("2d");
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    // Apply flip to match video view (mirror image)
    ctx.save();
    ctx.scale(-1, 1);
    ctx.translate(-canvas.width, 0);

    // Draw pose landmarks
    if (results.poseLandmarks) {
      drawingUtils.drawConnectors(ctx, results.poseLandmarks, Holistic.POSE_CONNECTIONS, { color: "#00FF00", lineWidth: 2 });
      drawingUtils.drawLandmarks(ctx, results.poseLandmarks, { color: "#FF0000", lineWidth: 1 });
    }

    // Draw left hand landmarks
    if (results.leftHandLandmarks) {
      drawingUtils.drawConnectors(ctx, results.leftHandLandmarks, Holistic.HAND_CONNECTIONS, { color: "#00FFFF", lineWidth: 2 });
      drawingUtils.drawLandmarks(ctx, results.leftHandLandmarks, { color: "#FF00FF", lineWidth: 1 });
    }

    // Draw right hand landmarks
    if (results.rightHandLandmarks) {
      drawingUtils.drawConnectors(ctx, results.rightHandLandmarks, Holistic.HAND_CONNECTIONS, { color: "#FFA500", lineWidth: 2 });
      drawingUtils.drawLandmarks(ctx, results.rightHandLandmarks, { color: "#0000FF", lineWidth: 1 });
    }

    ctx.restore();
  };

  // Setup MediaPipe Holistic and Camera
  useEffect(() => {
    const holistic = new Holistic({
      locateFile: (file) => `https://cdn.jsdelivr.net/npm/@mediapipe/holistic/${file}`,
    });

    holistic.setOptions({
      modelComplexity: 0,
      smoothLandmarks: true,
      minDetectionConfidence: 0.5,
      minTrackingConfidence: 0.5,
    });

    holistic.onResults(onResults);

    if (videoRef.current) {
      const camera = new Camera(videoRef.current, {
        onFrame: async () => {
          await holistic.send({ image: videoRef.current });
        },
        width: 640,
        height: 480,
      });
      camera.start();
    }
  }, []);

  return (
    <div style={{ textAlign: "center", padding: "20px" }}>
      <h2>🧠 SignSpeakly Live Translator</h2>
      {error && <p style={{ color: "red", fontWeight: "bold" }}>{error}</p>}

      <div style={{ position: "relative", width: "80vw", maxWidth: "960px", margin: "auto" }}>
        <video
          ref={videoRef}
          autoPlay
          muted
          playsInline
          width="100%"
          style={{
            width: "100%",
            height: "auto",
            borderRadius: "10px",
            border: "4px solid #2e7d32",
            objectFit: "cover",
            transform: "scaleX(-1)", // Mirror the video
          }}
        />
        <canvas
          ref={canvasRef}
          width={640}
          height={480}
          style={{
            position: "absolute",
            top: 0,
            left: 0,
            width: "100%",
            height: "100%",
            pointerEvents: "none",
          }}
        />
      </div>

      <div style={{ marginTop: "24px", fontSize: "22px", fontWeight: "bold", color: "#2e7d32" }}>
        {currentPrediction || "⏳ Waiting for prediction..."}
      </div>

      <textarea
        readOnly
        value={sentence.trim()}
        rows={3}
        placeholder="Final translated sentence..."
        style={{
          marginTop: "16px",
          width: "85%",
          maxWidth: "800px",
          padding: "12px",
          fontSize: "18px",
          borderRadius: "8px",
          border: "1px solid #ccc",
          backgroundColor: "#f0fdf4",
          color: "#333",
        }}
      />
    </div>
  );
};

export default TranslationPage;
